scwin.openOzPopup = async function(data){
    let opts = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };

    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", opts, data);
};

scwin.btn_Delete_onclick = async function (e) {

    if(await $c.win.confirm(E_MSG_CM_CRM_004)) {  //삭제하시겠습니까?

        for (var i = 0; i < ds_containerBookingList.getRowCount(); i++) {
            ds_containerBookingList.deleteRow(i);
        }

        for (var i = 0; i < ds_bookingDoorOrder.getRowCount(); i++) {
            ds_bookingDoorOrder.deleteRow(i);
        }

        ds_retrieveNo.removeAll();

        $c.sbm.execute(sbm_delete);
    }
};

scwin.f_Check = function(idx) {
    ds_containerBookingList.setCellData(idx, "bkIo", "O");
    ds_containerBookingList.setCellData(idx, "cnttype1", "22GP");
    ds_containerBookingList.setCellData(idx, "cnttype2", "42GP");
    ds_containerBookingList.setCellData(idx, "cnttype3", "45GP");
    ds_containerBookingList.setRowPosition(idx);
};

scwin.f_validate = function(e) {
    if(ds_containerBookingList.getCellData(ds_containerBookingList.getRowPosition(), "custCd") == ""){ 
        return false;
    }
    return true;
}
scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    await $c.gus.cfAlertMsg(E_MSG_CM_INF_001);
    scwin.f_Set("INIT");
    ds_search.set("bkNo", ds_retrieveNo.getCellData(0, "bkNo"));    
    scwin.btn_retrieve_onclick();

};

scwin.sbm_delete_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return; 

    ds_search.setEmptyValue();
    scwin.f_Set("INIT");
    ds_containerBookingList.removeAll();
    ds_bookingDoorOrder.removeAll();
    $c.gus.cfAlertMsg(E_MSG_CM_INF_004);
};

scwin._openMenu = function (title, path, menuId, param) {
	$c.win.openMenu(title, path, menuId, param || {});
};

scwin.btn_find_onclick = function (e) {
    scwin._openMenu(
        "Booking Search",
        "/ui/il/seaout/sobk/se_103_01_01b.xml",
        "se_103_01_01b.xml",
        { hhio: "O" }
    );
};

scwin.f_AddRow = function (e) {
    ds_bookingDoorOrder.insertRow(ds_bookingDoorOrder.getRowCount());
    ds_bookingDoorOrder.setCellData(ds_bookingDoorOrder.getRowCount()-1, "kcomcd", scwin.hd_kcomcd);
}

scwin.f_DelRow = function (e) {
    if(ds_search.get("bkNo") == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
        return;
    } else {
        if(ds_bookingDoorOrder.getRowStatus(ds_bookingDoorOrder.getRowPosition()) == "C"){
            ds_bookingDoorOrder.removeRow(ds_bookingDoorOrder.getRowPosition());
        } else {
            ds_bookingDoorOrder.deleteRow(ds_bookingDoorOrder.getRowPosition());
        }
    }
}

scwin.f_CancelRow = function (e){
    if(ds_search.get("bkNo") == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); // 해당되는 자료가 존재하지 않습니다
        return;
    } else {
         if(ds_bookingDoorOrder.getRowStatus(ds_bookingDoorOrder.getRowPosition()) == "C"){
            ds_bookingDoorOrder.removeRow(ds_bookingDoorOrder.getRowPosition());
        } else {
            ds_bookingDoorOrder.undoRow(ds_bookingDoorOrder.getRowPosition());
        }
    }
}

